<?php require 'vendor/autoload.php'; require 'bootstrap/app.php'; $app = app(); $app->make('Illuminate\Contracts\Console\Kernel')->bootstrap(); try { echo \App\Models\Projects::leftJoin('clients', 'projects.client_id', '=', 'clients.id')->leftJoin(\Illuminate\Support\Facades\DB::raw('(SELECT project_id, SUM(paid) as total_paid FROM recoveries GROUP BY project_id) as rec_totals'), 'projects.id', '=', 'rec_totals.project_id')->toSql(); } catch(\Exception $e) { echo $e->getMessage(); }
